# :Description: Scanne l'arborescence et enregistre metas et datas si disponibles
# :Inputs: target_path (str)
# :Outputs: insertion en base de données (tables metas, datas)

import os
import json
from models.Cognition.Memoria_Reflexa.actions.get_database_connection import get_database_connection
from models.Cognition.Memoria_Reflexa.actions.log import log
from models.Cognition.Memoria_Reflexa.actions.todo import todo

# Connexion à la base de données
db = get_database_connection()
cursor = db.cursor()

def scan_register_elements(target_path):
    """
    Parcourt les fichiers et enregistre metas + datas associées si présentes.
    """
    if not os.path.exists(target_path):
        log(f"Le chemin spécifié {target_path} n'existe pas.", "ERROR")
        return False

    for root, dirs, files in os.walk(target_path):
        for file in files:
            if file.endswith(".py"):
                full_path = os.path.join(root, file)
                try:
                    with open(full_path, "r", encoding="utf-8") as f:
                        lines = f.readlines()

                    metas = {}
                    metas_section = False

                    for line in lines:
                        line = line.strip()
                        if line.startswith("# :"):
                            metas_section = True
                            try:
                                key, value = line[3:].split(":", 1)
                                metas[key.strip()] = value.strip()
                            except ValueError:
                                continue
                        elif metas_section and not line.startswith("# :"):
                            break

                    if metas:
                        # Enregistrement des metas
                        cursor.execute("INSERT INTO metas (object_id, metas) VALUES (?, ?)", (metas.get("File", file), json.dumps(metas)))
                        log(f"Metas enregistrés pour {file}", "DEBUG")

                        # Gestion optionnelle des datas
                        if "Data" in metas:
                            try:
                                datas = json.loads(metas["Data"])
                                cursor.execute("INSERT INTO datas (object_id, datas) VALUES (?, ?)", (metas.get("File", file), json.dumps(datas)))
                                log(f"Datas enregistrés pour {file}", "DEBUG")
                            except Exception as e:
                                todo(f"Analyser datas dans {file} : erreur {e}")
                        else:
                            todo(f"Ajouter datas pour {file} si nécessaire.")

                except Exception as e:
                    log(f"Erreur lors du traitement de {file} : {e}", "ERROR")

    db.commit()
    db.close()
    log("Scan et enregistrement terminé.", "SUCCESS")"}
